const CUSTOM_IMG_KEYS = ["mercury", "venus", "saturn"];

const STARS = Array.from({ length: 220 }, (_, i) => {
  const s = Math.random();
  return {
    id: i,
    x: Math.random() * 100,
    y: Math.random() * 100,
    size: s * 2 + 0.3,
    op: s * 0.65 + 0.15,
    delay: Math.random() * 5,
    dur: 2 + Math.random() * 3,
  };
});

function PlanetBall({ planet, size, isActive, isLocked }) {
  const isCustom = CUSTOM_IMG_KEYS.includes(planet.key);
  return (
    <div
      className="timeline-planet-ball"
      style={{
        width: size,
        height: size,
        boxShadow: isActive
          ? `0 0 60px ${planet.glow}99,0 0 120px ${planet.glow}30,0 30px 80px rgba(0,0,0,.9)`
          : isLocked
            ? "0 12px 40px rgba(0,0,0,.96),inset 0 0 28px rgba(0,0,0,.6)"
            : `0 0 22px ${planet.glow}55,0 16px 45px rgba(0,0,0,.8)`,
      }}
    >
      <img
        src={IMG[planet.key]}
        alt={planet.name}
        className={`timeline-planet-img ${isCustom ? "timeline-planet-img--custom" : "timeline-planet-img--default"}`}
        style={{
          filter: isLocked
            ? "brightness(.2) saturate(.12)"
            : isActive
              ? "brightness(1.18) saturate(1.3) contrast(1.06)"
              : "brightness(.78) saturate(.85)",
        }}
      />
      <div
        className="timeline-planet-shade"
        style={{
          background: isLocked
            ? "radial-gradient(circle at 36% 36%,rgba(0,0,0,0) 0%,rgba(0,0,0,.12) 36%,rgba(0,0,0,.97) 70%)"
            : "radial-gradient(circle at 36% 36%,rgba(0,0,0,0) 0%,rgba(0,0,0,.04) 36%,rgba(0,0,0,.76) 70%)",
        }}
      />
      {!isLocked && <div className="timeline-planet-specular" />}
      {!isLocked && (
        <div
          className="timeline-planet-rim"
          style={{
            boxShadow: `inset 0 0 ${isActive ? 26 : 10}px ${planet.glow}${isActive ? "58" : "20"}`,
            border: `1px solid ${planet.glow}${isActive ? "42" : "16"}`,
          }}
        />
      )}
      {isLocked && (
        <div className="timeline-planet-lock-icon">
          <svg
            width={size * 0.32}
            height={size * 0.38}
            viewBox="0 0 24 28"
            fill="none"
          >
            <rect
              x="3"
              y="12"
              width="18"
              height="14"
              rx="2"
              fill="rgba(255,255,255,.09)"
              stroke="rgba(255,255,255,.16)"
              strokeWidth="1.2"
            />
            <path
              d="M8 12V8a4 4 0 0 1 8 0v4"
              stroke="rgba(255,255,255,.16)"
              strokeWidth="1.2"
              strokeLinecap="round"
            />
            <circle cx="12" cy="18" r="1.5" fill="rgba(255,255,255,.2)" />
          </svg>
        </div>
      )}
    </div>
  );
}

function SaturnRings({ size, isActive, glow }) {
  return (
    <div
      className="timeline-saturn-rings"
      style={{ width: size * 2.4, height: size * 2.4 }}
    >
      <div
        className="timeline-saturn-ring-outer"
        style={{
          width: size * 2,
          height: size * 2,
          border: `${isActive ? 8 : 4}px solid ${glow}88`,
          boxShadow: `0 0 ${isActive ? 32 : 12}px ${glow}55,inset 0 0 ${isActive ? 20 : 8}px ${glow}30`,
          margin: "auto",
          marginTop: (size * 2.4 - size * 2) / 2,
        }}
      >
        <div
          className="timeline-saturn-ring-inner"
          style={{
            border: `${isActive ? 4 : 2}px solid ${glow}44`,
            boxShadow: `0 0 ${isActive ? 16 : 6}px ${glow}28`,
          }}
        />
      </div>
    </div>
  );
}

function Planet({ planet, isActive, onClick }) {
  const locked = planet.status === "locked";
  const sz = isActive ? 155 : 74;
  return (
    <div
      onClick={() => !locked && onClick(planet.id)}
      className={`timeline-planet-wrap ${isActive ? "timeline-planet-wrap--active" : "timeline-planet-wrap--inactive"} ${locked ? "timeline-planet-wrap--locked" : "timeline-planet-wrap--unlocked"}`}
    >
      {isActive && (
        <>
          <div
            className="timeline-aura"
            style={{
              background: `radial-gradient(circle,${planet.glow}18 0%,${planet.glow}07 44%,transparent 68%)`,
            }}
          />
          {[1.65, 2.18].map((m, i) => (
            <div
              key={i}
              className="timeline-orbit-ring"
              style={{
                width: sz * m,
                height: sz * m,
                border: `1px solid ${planet.glow}${i === 0 ? "22" : "0f"}`,
                animation: `orbitSpin ${i === 0 ? 22 : 40}s linear infinite ${i === 1 ? "reverse" : ""}`,
              }}
            >
              {i === 0 && (
                <div
                  className="timeline-orbit-dot"
                  style={{
                    background: planet.glow,
                    boxShadow: `0 0 10px ${planet.glow}`,
                  }}
                />
              )}
            </div>
          ))}
          <div
            className="timeline-constellation"
            style={{ width: sz + 48, height: sz + 48 }}
          >
            <svg width="100%" height="100%" viewBox="0 0 203 203">
              {[
                [34, 50],
                [101, 18],
                [168, 56],
                [176, 104],
                [150, 158],
                [96, 178],
                [38, 148],
                [16, 94],
              ].map(([x, y], i, arr) => (
                <g key={i}>
                  <line
                    x1={x}
                    y1={y}
                    x2={arr[(i + 1) % arr.length][0]}
                    y2={arr[(i + 1) % arr.length][1]}
                    stroke={planet.glow}
                    strokeWidth=".5"
                    strokeOpacity=".38"
                  />
                  <circle
                    cx={x}
                    cy={y}
                    r="2.5"
                    fill={planet.glow}
                    fillOpacity=".72"
                  />
                </g>
              ))}
            </svg>
          </div>
        </>
      )}

      {planet.hasSaturnRing && (
        <SaturnRings size={sz} isActive={isActive} glow={planet.glow} />
      )}

      <PlanetBall
        planet={planet}
        size={sz}
        isActive={isActive}
        isLocked={locked}
      />

      <div
        className="timeline-planet-label"
        style={{ marginTop: isActive ? 22 : 13 }}
      >
        {isActive && (
          <div className="timeline-planet-tag" style={{ color: planet.glow }}>
            PLANET
          </div>
        )}
        <div
          className="timeline-planet-name"
          style={{
            fontSize: isActive ? 14 : 8,
            fontWeight: isActive ? 700 : 500,
            color: locked ? "#2a2e38" : isActive ? planet.glow : "#65707e",
            letterSpacing: isActive ? 4 : 2,
            textShadow: isActive ? `0 0 28px ${planet.glow}99` : "none",
          }}
        >
          {planet.name}
        </div>
        {isActive && (
          <div className="timeline-planet-subtitle">{planet.subtitle}</div>
        )}
        <div
          className="timeline-planet-mission"
          style={{
            fontSize: isActive ? 10 : 8,
            color: locked ? "#222630" : isActive ? "#4e6070" : "#303840",
            marginTop: isActive ? 5 : 3,
          }}
        >
          {locked ? "LOCKED" : `${planet.mission} · lv ${planet.levels}`}
        </div>
      </div>

      {isActive && (
        <div
          className="timeline-blink-dot"
          style={{
            background: planet.glow,
            boxShadow: `0 0 10px ${planet.glow}`,
          }}
        />
      )}
    </div>
  );
}

function Line({ fromActive, glow }) {
  return (
    <div className="timeline-line">
      {[...Array(4)].map((_, i) => (
        <div
          key={i}
          className="timeline-line-seg"
          style={{
            background: fromActive
              ? `linear-gradient(90deg,${glow}70,${glow}12)`
              : "#12182a",
          }}
        />
      ))}
    </div>
  );
}

export default function Timeline() {
  const [activeId, setActiveId] = useState(4);
  const [vis, setVis] = useState(true);
  const scrollRef = useRef(null);
  const active = PLANETS.find((p) => p.id === activeId);

  const pick = (id) => {
    if (id === activeId) return;
    setVis(false);
    setTimeout(() => {
      setActiveId(id);
      setVis(true);
    }, 260);
  };

  const scrollToActive = (id) => {
    const c = scrollRef.current;
    if (!c) return;
    const el = c.querySelector(`[data-pid="${id}"]`);
    if (el) {
      const cr = c.getBoundingClientRect(),
        er = el.getBoundingClientRect();
      c.scrollBy({
        left: er.left + er.width / 2 - cr.left - cr.width / 2,
        behavior: "smooth",
      });
    }
  };

  useEffect(() => {
    scrollToActive(activeId);
  }, [activeId]);

  const goLeft = () => {
    const idx = PLANETS.findIndex((p) => p.id === activeId);
    if (idx > 0) {
      const prev = PLANETS[idx - 1];
      if (prev.status !== "locked") pick(prev.id);
    }
  };
  const goRight = () => {
    const idx = PLANETS.findIndex((p) => p.id === activeId);
    if (idx < PLANETS.length - 1) {
      const next = PLANETS[idx + 1];
      if (next.status !== "locked") pick(next.id);
    }
  };

  return (
    <div className="timeline-root">
      {/* Stars */}
      <div className="timeline-stars">
        {STARS.map((s) => (
          <div
            key={s.id}
            className="timeline-star"
            style={{
              left: `${s.x}%`,
              top: `${s.y}%`,
              width: s.size,
              height: s.size,
              "--op": s.op,
              opacity: s.op,
              animation: `twinkle ${s.dur}s ease-in-out ${s.delay}s infinite`,
            }}
          />
        ))}
      </div>

      {/* Nebula */}
      <div className="timeline-nebula" />

      {/* Scan line */}
      <div className="timeline-scan-wrap">
        <div className="timeline-scan-line" />
      </div>

      {/* Header */}
      <header className="timeline-header">
        <div className="timeline-header-left">
          <span className="timeline-logo">
            NOVA<span className="timeline-logo-dim">GRAPHIX</span>
          </span>
          <div className="timeline-divider" />
          <div className="timeline-bars">
            {[...Array(5)].map((_, i) => (
              <div
                key={i}
                className={`timeline-bar ${i < 3 ? "timeline-bar--on" : "timeline-bar--off"}`}
              />
            ))}
          </div>
        </div>
        <div className="timeline-header-center">
          <div className="timeline-user-badge">
            <div className="timeline-user-dot" />
            <span className="timeline-user-name">
              HUNTER <span>13</span>
            </span>
            <span className="timeline-user-mastery">
              MASTERY <span>454.724</span>
            </span>
          </div>
          {[
            ["CREDITS", "156 588", "#d8a830"],
            ["PLATINUM", "1 200", "#a0c0e0"],
          ].map(([l, v, c]) => (
            <div key={l} style={{ textAlign: "right" }}>
              <div className="timeline-currency-label">{l}</div>
              <div className="timeline-currency-val" style={{ color: c }}>
                {v}
              </div>
            </div>
          ))}
        </div>
        <div className="timeline-header-right">
          {["⚙", "🔔", "❄", "✕"].map((ic, i) => (
            <button key={i} className="timeline-icon-btn">
              {ic}
            </button>
          ))}
        </div>
      </header>

      {/* Main */}
      <div className="timeline-main">
        {/* Active planet info */}
        <div
          className={`timeline-info ${vis ? "timeline-info--visible" : "timeline-info--hidden"}`}
        >
          <div
            className="timeline-info__distance"
            style={{ color: active.glow }}
          >
            {active.distance} from Sol
          </div>
          <div
            className="timeline-info__name"
            style={{
              textShadow: `0 0 38px ${active.glow}72,0 0 76px ${active.glow}24`,
            }}
          >
            {active.name}
          </div>
          <div className="timeline-info__desc">{active.description}</div>
        </div>

        {/* Scroll area with arrows */}
        <div className="timeline-scroll-area">
          <button
            className="timeline-arrow timeline-arrow--left"
            onClick={goLeft}
          >
            &#9664;
          </button>

          <div ref={scrollRef} className="timeline-scroll">
            <div className="timeline-track">
              {PLANETS.map((planet, i) => (
                <div key={planet.id} className="timeline-track-item">
                  <div data-pid={planet.id}>
                    <Planet
                      planet={planet}
                      isActive={planet.id === activeId}
                      onClick={pick}
                    />
                  </div>
                  {i < PLANETS.length - 1 && (
                    <Line
                      fromActive={planet.id === activeId}
                      glow={planet.glow}
                    />
                  )}
                </div>
              ))}
            </div>
          </div>

          <button
            className="timeline-arrow timeline-arrow--right"
            onClick={goRight}
          >
            &#9654;
          </button>
        </div>

        {/* Bottom bar */}
        <div className="timeline-bottom-bar" style={{ opacity: vis ? 1 : 0 }}>
          {active.status !== "locked" ? (
            <>
              {[
                ["OBJECTIVE", active.mission],
                ["LEVEL RANGE", active.levels],
                ["STATUS", active.status.toUpperCase()],
                ["DISTANCE", active.distance],
              ].map(([label, val]) => (
                <div key={label} className="timeline-stat-card">
                  <div className="timeline-stat-label">{label}</div>
                  <div
                    className="timeline-stat-val"
                    style={{
                      color:
                        active.status === "active" ? active.glow : "#4e6070",
                      textShadow:
                        active.status === "active"
                          ? `0 0 12px ${active.glow}60`
                          : "none",
                    }}
                  >
                    {val}
                  </div>
                </div>
              ))}
              <button
                className="timeline-launch-btn"
                style={{
                  background: `linear-gradient(135deg,${active.glow}28,${active.glow}0d)`,
                  border: `1px solid ${active.glow}40`,
                  color: active.glow,
                  boxShadow: `0 0 22px ${active.glow}1c`,
                }}
                onMouseEnter={(e) => {
                  e.currentTarget.style.boxShadow = `0 0 40px ${active.glow}60`;
                  e.currentTarget.style.background = `linear-gradient(135deg,${active.glow}46,${active.glow}22)`;
                }}
                onMouseLeave={(e) => {
                  e.currentTarget.style.boxShadow = `0 0 22px ${active.glow}1c`;
                  e.currentTarget.style.background = `linear-gradient(135deg,${active.glow}28,${active.glow}0d)`;
                }}
              >
                &#9654;{" "}
                {active.status === "completed"
                  ? "REPLAY MISSION"
                  : "LAUNCH MISSION"}
              </button>
            </>
          ) : (
            <div className="timeline-locked-msg">
              &mdash; SECTOR LOCKED &mdash; COMPLETE PREVIOUS MISSIONS TO UNLOCK
              &mdash;
            </div>
          )}
        </div>
      </div>

      {/* Corner brackets */}
      {[
        { top: 58, left: 0, bt: true, bl: true },
        { top: 58, right: 0, bt: true, br: true },
        { bottom: 0, left: 0, bb: true, bl: true },
        { bottom: 0, right: 0, bb: true, br: true },
      ].map((pos, i) => (
        <div
          key={i}
          className="timeline-corner"
          style={{
            top: pos.top,
            bottom: pos.bottom,
            left: pos.left,
            right: pos.right,
            borderTop: pos.bt ? "1px solid #0e1820" : "none",
            borderBottom: pos.bb ? "1px solid #0e1820" : "none",
            borderLeft: pos.bl ? "1px solid #0e1820" : "none",
            borderRight: pos.br ? "1px solid #0e1820" : "none",
          }}
        />
      ))}
    </div>
  );
}
